  if (timeout > 0) s += `, ${timeout} timeout`;
  if (unknown > 0) s += `, ${unknown} unknown`;
  s = `${s} (native)`;
  if (stalls > 0) s += `; ${stalls} narrated stall${stalls === 1 ? '' : 's'} (heuristic)`;
